import React, { useState, useEffect } from 'react';
import { Container, Typography, Grid, Paper, Box } from '@mui/material';
import Navbar from '../common/Navbar';
import authService from '../../services/authService';
import gradeService from '../../services/gradeService';

function StudentDashboard() {
  const [averageGrade, setAverageGrade] = useState(0);
  const user = authService.getCurrentUser();

  useEffect(() => {
    loadGrades();
  }, []);

  const loadGrades = async () => {
    try {
      // In real app, get student ID from user profile
      // const response = await gradeService.getStudentAverage(studentId);
      // setAverageGrade(response.data);
    } catch (error) {
      console.error('Error loading grades:', error);
    }
  };

  return (
    <>
      <Navbar />
      <Container maxWidth="lg" sx={{ mt: 4, mb: 4 }}>
        <Typography variant="h4" gutterBottom>
          Student Dashboard
        </Typography>
        <Grid container spacing={3}>
          <Grid item xs={12} md={6}>
            <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', height: 140 }}>
              <Typography variant="h6" gutterBottom>
                My Courses
              </Typography>
              <Typography variant="body2">
                View enrolled courses
              </Typography>
            </Paper>
          </Grid>
          <Grid item xs={12} md={6}>
            <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', height: 140 }}>
              <Typography variant="h6" gutterBottom>
                My Grades
              </Typography>
              <Typography variant="h3">
                {averageGrade.toFixed(2)}
              </Typography>
              <Typography variant="caption">Average Grade</Typography>
            </Paper>
          </Grid>
          <Grid item xs={12} md={6}>
            <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', height: 140 }}>
              <Typography variant="h6" gutterBottom>
                My Attendance
              </Typography>
              <Typography variant="body2">
                View attendance records
              </Typography>
            </Paper>
          </Grid>
          <Grid item xs={12} md={6}>
            <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', height: 140 }}>
              <Typography variant="h6" gutterBottom>
                Course Schedule
              </Typography>
              <Typography variant="body2">
                View your schedule
              </Typography>
            </Paper>
          </Grid>
        </Grid>
        <Box sx={{ mt: 3 }}>
          <Typography variant="body1">
            Welcome {user?.firstName}! View your courses, grades, and attendance here.
          </Typography>
        </Box>
      </Container>
    </>
  );
}

export default StudentDashboard;
